import{_ as s,C as i,o as e,c as E,a2 as n,E as p}from"./chunks/framework.BnBoz4Zl.js";const u=JSON.parse('{"title":"第 25 章 可靠自动化：预检、确认、日志与回退","description":"自动化不是“定时运行成功”就可靠。真正可靠的工作流知道输入是否准备好、同类任务是否已在运行、何时需要人工确认、失败后如何停止和恢复。 每周检查一个练习目录中的新增文件，生成索引和异常清单。流程只读源文件；若发现已有同类批次运行、源目录不存在或输出冲突，则停止并报告，不重复启动。","frontmatter":{},"headers":[],"relativePath":"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 25 章 自动化工作流的可靠性/index.md","filePath":"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 25 章 自动化工作流的可靠性/index.md","lastUpdated":1784100816000}'),t={name:"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 25 章 自动化工作流的可靠性/index.md"};function o(r,a,A,d,c,h){const l=i("MermaidDiagram");return e(),E("div",null,[a[0]||(a[0]=n('<h1 id="第-25-章-可靠自动化-预检、确认、日志与回退" tabindex="-1">第 25 章 可靠自动化：预检、确认、日志与回退 <a class="header-anchor" href="#第-25-章-可靠自动化-预检、确认、日志与回退" aria-label="Permalink to &quot;第 25 章 可靠自动化：预检、确认、日志与回退&quot;">​</a></h1><p>自动化不是“定时运行成功”就可靠。真正可靠的工作流知道输入是否准备好、同类任务是否已在运行、何时需要人工确认、失败后如何停止和恢复。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>定期汇总公开信息或指定目录中的材料。</li><li>批量生成索引、报告、数据质量清单。</li><li>定期检查文件、任务状态和异常。</li><li>把稳定的手工流程转成可重复执行任务。</li></ul><h2 id="上线前七项检查" tabindex="-1">上线前七项检查 <a class="header-anchor" href="#上线前七项检查" aria-label="Permalink to &quot;上线前七项检查&quot;">​</a></h2><ol><li>输入来源是否稳定、完整并获得授权。</li><li>是否存在仍在运行的同类任务，避免重复启动。</li><li>工作目录和输出目录是否正确。</li><li>重复运行是否会覆盖、重复写入或产生冲突。</li><li>哪些动作必须等待明确人工确认。</li><li>失败后如何停止、重试和回退。</li><li>日志、责任人和验收结果存放在哪里。</li></ol><h2 id="可靠流程" tabindex="-1">可靠流程 <a class="header-anchor" href="#可靠流程" aria-label="Permalink to &quot;可靠流程&quot;">​</a></h2>',7)),p(l,{graph:"flowchart%20LR%0A%20%20A%5B%E5%8F%AA%E8%AF%BB%E9%A2%84%E6%A3%80%5D%20--%3E%20B%7B%E8%BE%93%E5%85%A5%E4%B8%8E%E6%9D%83%E9%99%90%E5%90%88%E6%A0%BC%3F%7D%0A%20%20B%20--%20%E5%90%A6%20--%3E%20C%5B%E5%81%9C%E6%AD%A2%E5%B9%B6%E6%8A%A5%E5%91%8A%E7%BC%BA%E5%8F%A3%5D%0A%20%20B%20--%20%E6%98%AF%20--%3E%20D%5B%E8%84%B1%E6%95%8F%E5%B0%8F%E6%A0%B7%E6%9C%AC%5D%0A%20%20D%20--%3E%20E%7B%E6%A0%B7%E6%9C%AC%E9%AA%8C%E6%94%B6%3F%7D%0A%20%20E%20--%20%E5%90%A6%20--%3E%20F%5B%E4%BF%AE%E6%AD%A3%E8%A7%84%E5%88%99%5D%0A%20%20F%20--%3E%20D%0A%20%20E%20--%20%E6%98%AF%20--%3E%20G%5B%E6%AD%A3%E5%BC%8F%E8%BF%90%E8%A1%8C%5D%0A%20%20G%20--%3E%20H%5B%E6%97%A5%E5%BF%97%E4%B8%8E%E7%BB%93%E6%9E%9C%E6%A3%80%E6%9F%A5%5D%0A%20%20H%20--%3E%20I%7B%E9%9C%80%E8%A6%81%E5%A4%96%E5%8F%91%E6%88%96%E5%86%99%E5%85%A5%3F%7D%0A%20%20I%20--%20%E6%98%AF%20--%3E%20J%5B%E7%AD%89%E5%BE%85%E4%BA%BA%E5%B7%A5%E7%A1%AE%E8%AE%A4%5D%0A%20%20I%20--%20%E5%90%A6%20--%3E%20K%5B%E5%AE%8C%E6%88%90%E5%B9%B6%E5%BD%92%E6%A1%A3%E8%AE%B0%E5%BD%95%5D%0A%20%20J%20--%3E%20K%0A"}),a[1]||(a[1]=n(`<h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>每周检查一个练习目录中的新增文件，生成索引和异常清单。流程只读源文件；若发现已有同类批次运行、源目录不存在或输出冲突，则停止并报告，不重复启动。</p><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请设计一项可停止、可重试、可回退的自动化任务。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>触发方式：{时间或事件}</span></span>
<span class="line"><span>输入来源：{来源}</span></span>
<span class="line"><span>工作目录：{目录}</span></span>
<span class="line"><span>输出物：{文件或记录}</span></span>
<span class="line"><span>验收标准：{标准}</span></span>
<span class="line"><span>人工确认点：{外发/写入/覆盖/审批前}</span></span>
<span class="line"><span>禁止动作：{动作}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每次运行前检查输入、权限、输出冲突和同类任务状态；</span></span>
<span class="line"><span>先用脱敏小样本运行；</span></span>
<span class="line"><span>为每一步记录开始、完成、跳过、失败和原因；</span></span>
<span class="line"><span>错误达到停止条件时立即停止，不无限重试；</span></span>
<span class="line"><span>没有明确确认，不执行外发、删除、覆盖和业务写入。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>首次上线、规则变化和输入结构变化。</li><li>样本扩大为批量运行之前。</li><li>外发、覆盖、删除、审批和正式写入之前。</li><li>连续失败、结果异常或恢复运行之前。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>运行说明包含触发、输入、输出、权限和责任人。</li><li>日志能区分未运行、运行中、成功、部分成功和失败。</li><li>重复执行不会产生重复结果或覆盖原件。</li><li>停止、重试和回退经过合成样本测试。</li></ul><h2 id="常见弯路与安全边界" tabindex="-1">常见弯路与安全边界 <a class="header-anchor" href="#常见弯路与安全边界" aria-label="Permalink to &quot;常见弯路与安全边界&quot;">​</a></h2><ul><li>任务安静不代表失败，应检查进程、日志和输出状态。</li><li>用定时轮询代替人的明确确认，会误触发后续动作。</li><li>只记录成功日志，失败时无法复盘。日志必须覆盖所有状态。</li><li>不让自动化承担审批、专业判断和不可逆操作。</li></ul>`,10))])}const _=s(t,[["render",o]]);export{u as __pageData,_ as default};
